// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import {
  getPendingCaptains,
  approveRider,
  rejectRider,
} from "../../services/api";
import {
  Box,
  Paper,
  Table,
  TableHead,
  TableBody,
  TableRow,
  TableCell,
  Button,
  Stack,
  Dialog,
  DialogTitle,
  DialogContent,
  Typography,
  Card,
  CardMedia,
  CardActions,
} from "@mui/material";

export default function PendingCaptains() {
  const [pendingCaptains, setPendingCaptains] = useState([]);
  const [selectedRider, setSelectedRider] = useState(null);
  const [openDocsModal, setOpenDocsModal] = useState(false);

  useEffect(() => {
    fetchPendingCaptains();
  }, []);

  const fetchPendingCaptains = async () => {
    try {
      const res = await getPendingCaptains();
      setPendingCaptains(res?.data?.data || []);
    } catch (err) {
      console.error(err);
    }
  };

  const handleApprove = async (id) => {
    try {
      await approveRider(id);
      setPendingCaptains((prev) => prev.filter((c) => c._id !== id));
    } catch (err) {
      console.error(err);
    }
  };

  const handleReject = async (id) => {
    try {
      await rejectRider(id);
      setPendingCaptains((prev) => prev.filter((c) => c._id !== id));
    } catch (err) {
      console.error(err);
    }
  };

  const handleViewDocuments = (rider) => {
    setSelectedRider(rider);
    setOpenDocsModal(true);
  };

  const handleCloseDocuments = () => {
    setSelectedRider(null);
    setOpenDocsModal(false);
  };

  return (
    <Box sx={{ p: 3 }}>
      <Paper sx={{ p: 3 }}>
        <Typography variant="h5" gutterBottom>Pending Details</Typography>
        <Table>
          <TableHead>
            <TableRow>
              <TableCell><strong>Name</strong></TableCell>
              <TableCell><strong>Email</strong></TableCell>
              <TableCell><strong>Mobile</strong></TableCell>
              <TableCell><strong>Role</strong></TableCell>
              <TableCell><strong>Documents</strong></TableCell>
              <TableCell><strong>Actions</strong></TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {pendingCaptains.map((rider) => (
              <TableRow key={rider._id}>
                <TableCell>{rider.fullName}</TableCell>
                <TableCell>{rider.email}</TableCell>
                <TableCell>{rider.mobile}</TableCell>
                <TableCell>{rider.role}</TableCell>
                <TableCell>
                  <Button variant="outlined" size="small" onClick={() => handleViewDocuments(rider)}>
                    View Documents
                  </Button>
                </TableCell>
                <TableCell>
                  <Stack direction="row" spacing={1}>
                    <Button variant="contained" color="success" size="small" onClick={() => handleApprove(rider._id)}>Approve</Button>
                    <Button variant="contained" color="error" size="small" onClick={() => handleReject(rider._id)}>Reject</Button>
                  </Stack>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </Paper>

      {/* Documents Modal */}
      <Dialog open={openDocsModal} onClose={handleCloseDocuments} maxWidth="md" fullWidth>
        <DialogTitle>Rider Details {selectedRider?.fullName ? `- ${selectedRider.fullName}` : ""}</DialogTitle>
        <DialogContent dividers>
          {selectedRider && (
            <Box mb={3}>
              <Typography><strong>Name:</strong> {selectedRider.fullName}</Typography>
              <Typography><strong>Email:</strong> {selectedRider.email}</Typography>
              <Typography><strong>Mobile:</strong> {selectedRider.mobile}</Typography>
              <Typography><strong>Role:</strong> {selectedRider.role}</Typography>
              <Typography><strong>Status:</strong> {selectedRider.approvalStatus || "pending"}</Typography>
              <Typography><strong>Created At:</strong> {selectedRider.createdAt ? new Date(selectedRider.createdAt).toLocaleString() : "-"}</Typography>
            </Box>
          )}

          <Typography variant="h6" gutterBottom>Documents</Typography>

          {selectedRider?.documents ? (
            (() => {
              const docs = Array.isArray(selectedRider.documents)
                ? selectedRider.documents
                : Object.values(selectedRider.documents);

              if (docs.length === 0) return <Typography>No documents uploaded.</Typography>;

              return (
                <Stack spacing={2} direction="row" flexWrap="wrap">
                  {docs.map((doc, idx) => {
                    const url = doc?.url || doc?.location || doc?.secure_url || doc?.path || doc;
                    const name = doc?.name || `Document ${idx + 1}`;
                    const isImage = /\.(jpe?g|png|gif|webp)$/i.test(url || "");
                    return (
                      <Card key={idx} sx={{ width: 250 }}>
                        {isImage ? (
                          <CardMedia component="img" height="180" image={url} alt={name} sx={{ objectFit: "contain" }} />
                        ) : (
                          <Box sx={{ height: 180, display: "flex", alignItems: "center", justifyContent: "center", bgcolor: "#f5f5f5" }}>
                            <Typography>{name}</Typography>
                          </Box>
                        )}
                        <CardActions>
                          <Button size="small" onClick={() => window.open(url, "_blank")}>View</Button>
                        </CardActions>
                      </Card>
                    );
                  })}
                </Stack>
              );
            })()
          ) : (
            <Typography>No documents uploaded.</Typography>
          )}
        </DialogContent>
      </Dialog>
    </Box>
  );
}
